-- -- @(#) $GenPackageDir$/$GenFileName$ $MssDoubleDashScriptLicense$ delimiter //// create function $lower DbSchemaName$.$sp_next_tableidgen$( $reference Dispenser reference PrimaryKeyIndex iterate Columns( first sparg_TableCol each sparg_CommaTableCol )$ ) returns smallint modifies sql data not deterministic begin declare SliceId smallint default $Slice$; declare NextId smallint;
if not exists ( select * from $lower DbSchemaName$.$reference Dispenser DbTableName$_idg16 where slice_id = SliceId$reference Dispenser reference PrimaryKeyIndex iterate Columns( each CreateSPNextTableIdGenPassExistsArg )$ ) then insert into $lower DbSchemaName$.$reference Dispenser DbTableName$_idg16 ($reference Dispenser reference PrimaryKeyIndex iterate Columns( each CreateSPNextTableIdGenInsertCol )$ slice_id, next_id ) values ($reference Dispenser reference PrimaryKeyIndex iterate Columns( each CreateSPNextTableIdGenInsertArg )$ SliceId, 1 ); end if;
select next_id into NextId from $lower DbSchemaName$.$reference Dispenser DbTableName$_idg16 where slice_id = SliceId$reference Dispenser reference PrimaryKeyIndex iterate Columns( each CreateSPNextTableIdGenPassWhereArg )$ for update;
update $lower DbSchemaName$.$reference Dispenser DbTableName$_idg16 set next_id = NextId + 1 where slice_id = SliceId$reference Dispenser reference PrimaryKeyIndex iterate Columns( each CreateSPNextTableIdGenPassWhereArg )$;
return NextId; end;////

